// ============================================================
// STORAGE
// ============================================================
// Storage localStorage uniquement — persistant sur tous les navigateurs
const storage = {
  async get(key) {
    try {
      const val = localStorage.getItem("fitrace_" + key);
      return val ? JSON.parse(val) : null;
    } catch { return null; }
  },
  async set(key, value) {
    try {
      localStorage.setItem("fitrace_" + key, JSON.stringify(value));
      // Synchro cloud transparente (sauf le pointeur de session, purement local à l'appareil)
      if (key !== "session_current" && typeof currentAthleteEmail !== "undefined" && currentAthleteEmail) {
        athleteKV.push(currentAthleteEmail, "fitrace_" + key, value);
      }
      return true;
    } catch (e) {
      console.error("Storage set error:", e);
      return false; // quota dépassé, navigation privée, stockage désactivé...
    }
  },
  async list(prefix) {
    try {
      const fullPrefix = "fitrace_" + prefix;
      const keys = [];
      for (let i = 0; i < localStorage.length; i++) {
        const k = localStorage.key(i);
        if (k && k.startsWith(fullPrefix)) {
          keys.push(k.replace("fitrace_", ""));
        }
      }
      return keys;
    } catch { return []; }
  },
  async del(key) {
    try { localStorage.removeItem("fitrace_" + key); } catch {}
  }
};

// ============================================================
// COMPTES & PROFILS ATHLÈTES — Supabase (partagé entre appareils)
// Remplace le stockage localStorage pour l'identité/le profil de l'athlète
// afin que le mode Coach puisse voir tous les athlètes, peu importe
// l'appareil où ils se sont inscrits. Tout le reste (nutrition, sommeil,
// planning, préférences UI...) reste en localStorage via `storage` ci-dessus.
// ============================================================
const athleteBackend = {
  async signup(email, name, password) {
    const { data, error } = await supabase.auth.signUp({ email, password, options: { data: { name } } });
    if (error) throw error;
    return data;
  },
  async login(email, password) {
    const { data, error } = await supabase.auth.signInWithPassword({ email, password });
    if (error) throw error;
    return { email: data.user.email, name: data.user.user_metadata?.name || "" };
  },
  async logout() {
    await supabase.auth.signOut();
  },
  async requestPasswordReset(email) {
    const { error } = await supabase.auth.resetPasswordForEmail(email, { redirectTo: window.location.origin });
    if (error) throw error;
  },
  async updatePassword(newPassword) {
    const { error } = await supabase.auth.updateUser({ password: newPassword });
    if (error) throw error;
  },
  async saveProfile(email, profile) {
    if (!email) throw new Error("saveProfile appelé sans email");
    const { error } = await supabase.from("athlete_profiles").upsert({ email, profile, updated_at: new Date().toISOString() });
    if (error) throw error;
    return true;
  },
  async getProfile(email) {
    const { data, error } = await supabase.from("athlete_profiles").select("profile").eq("email", email).maybeSingle();
    if (error) throw error;
    return data?.profile || null;
  },
  async listAthletes() {
    const { data, error } = await supabase.from("athlete_directory").select("email, profile, updated_at");
    if (error) throw error;
    return (data || []).map(row => ({ ...(row.profile || {}), email: row.email, _updatedAt: row.updated_at }));
  },
};

// ============================================================
// DONNÉES ATHLÈTE SECONDAIRES (nutrition, sommeil, douleurs, records...)
// — synchronisation cloud transparente par-dessus localStorage —
// Les lectures existantes (localStorage.getItem, inchangées) continuent de
// fonctionner exactement comme avant. `syncedStorage.set` écrit en local
// (identique à aujourd'hui) ET pousse une copie vers Supabase en arrière-plan,
// pour que ces données survivent au changement d'appareil et soient visibles
// par le coach. `hydrateFromCloud` est appelée une fois après connexion pour
// rapatrier ces données AVANT que le reste de l'app ne les lise.
// ============================================================
let currentAthleteEmail = null;

// File d'attente des synchros échouées (hors-ligne, erreur réseau...) :
// une seule entrée par clé (la dernière valeur gagne), persistée en local
// pour survivre à une fermeture de l'app, rejouée au retour en ligne.
const SYNC_PENDING_KEY = "fitrace_sync_pending";
const syncQueue = {
  load() { try { return JSON.parse(localStorage.getItem(SYNC_PENDING_KEY) || "{}"); } catch { return {}; } },
  save(q) { try { localStorage.setItem(SYNC_PENDING_KEY, JSON.stringify(q)); } catch {} },
  add(email, key, value) { const q = this.load(); q[key] = { email, value }; this.save(q); },
  remove(key) { const q = this.load(); if (key in q) { delete q[key]; this.save(q); } },
};

let flushingSyncQueue = false;
async function flushSyncQueue() {
  if (flushingSyncQueue) return;
  const q = syncQueue.load();
  const keys = Object.keys(q);
  if (!keys.length) return;
  flushingSyncQueue = true;
  try {
    for (const key of keys) {
      const { email, value } = q[key];
      try {
        const { error } = await supabase.rpc("kv_push", { p_email: email, p_key: key, p_value: value });
        if (!error) syncQueue.remove(key);
      } catch { break; } // toujours hors-ligne — on réessaiera au prochain passage
    }
  } finally { flushingSyncQueue = false; }
}
if (typeof window !== "undefined") {
  window.addEventListener("online", flushSyncQueue);
  setInterval(() => { if (navigator.onLine) flushSyncQueue(); }, 60000);
}

const athleteKV = {
  async pullAll(email) {
    const { data, error } = await supabase.rpc("kv_pull_all", { p_email: email });
    if (error) throw error;
    return data || []; // [{ key, value }, ...]
  },
  push(email, key, value) {
    if (!email) return;
    // Ne bloque jamais l'UI ; en cas d'échec la valeur est mise en file
    // et rejouée automatiquement (retour en ligne ou toutes les 60s).
    supabase.rpc("kv_push", { p_email: email, p_key: key, p_value: value }).then(({ error }) => {
      if (error) { console.error("Sync cloud échouée pour", key, error.message); syncQueue.add(email, key, value); }
      else syncQueue.remove(key);
    }).catch(() => syncQueue.add(email, key, value));
  },
};

// ── Couche réactive ──────────────────────────────────────────────
// Dès qu'une donnée est écrite (repas, sommeil, poids, hydratation...),
// on notifie l'app pour que TOUS les widgets qui recalculent à partir de
// localStorage (scores APEX/Fitness, anneaux, résumés, récupération...) se
// rafraîchissent ensemble, sans que chacun ait à s'abonner manuellement.
// Les notifications d'un même "tick" sont fusionnées (une seule mise à jour).
const dataListeners = new Set();
let dataChangeScheduled = false;
function notifyDataChange() {
  if (dataChangeScheduled) return;
  dataChangeScheduled = true;
  const run = () => { dataChangeScheduled = false; dataListeners.forEach(fn => { try { fn(); } catch {} }); };
  if (typeof queueMicrotask === "function") queueMicrotask(run);
  else Promise.resolve().then(run);
}

const syncedStorage = {
  // Remplace syncedStorage.set(key, value) — même effet local,
  // plus une synchronisation cloud en arrière-plan, plus une notification
  // réactive pour que les autres widgets se mettent à jour ensemble.
  set(key, value) {
    try { localStorage.setItem(key, JSON.stringify(value)); } catch (e) { console.error("localStorage set error:", e); }
    if (currentAthleteEmail) athleteKV.push(currentAthleteEmail, key, value);
    notifyDataChange();
  },
};

async function hydrateFromCloud(email) {
  currentAthleteEmail = email;
  try {
    const rows = await athleteKV.pullAll(email);
    for (const row of rows) {
      try { localStorage.setItem(row.key, JSON.stringify(row.value)); } catch {}
    }
  } catch (e) {
    console.error("Hydratation cloud échouée:", e);
  }
}

